_engine = None

def get_engine(db_url=None):
    global _engine
    if _engine:
        return _engine

    if not db_url:
        db_url = os.getenv('DATABASE_URL')
        if not db_url:
            if os.getenv('VERCEL') == '1':
                db_url = 'sqlite:////tmp/moviehub.db'
            else:
                db_url = 'sqlite:///moviehub.db'

    # SQLite의 경우 멀티스레드 환경(FastAPI + Scheduler)에서 check_same_thread=False 필요
    connect_args = {}
    if db_url.startswith('sqlite'):
        connect_args = {'check_same_thread': False}
    else:
        # Postgres 등 외부 DB 사용 시 연결 풀 설정 보강
        return create_engine(
            db_url,
            pool_size=5,
            max_overflow=10,
            pool_recycle=3600,
            pool_pre_ping=True
        )

    _engine = create_engine(db_url, connect_args=connect_args)
    return _engine

def get_session(engine=None):
    if not engine:
        engine = get_engine()
    Session = sessionmaker(bind=engine)
    return Session()

def init_db(engine=None):
    if not engine:
        engine = get_engine()
    Base.metadata.create_all(engine)

import os
import requests
from src.utils.logger import get_logger
from dotenv import load_dotenv

load_dotenv()
logger = get_logger("Notifier")

class TelegramNotifier:
    def __init__(self):
        self.token = os.getenv("TELEGRAM_BOT_TOKEN")
        self.chat_id = os.getenv("TELEGRAM_CHAT_ID")
        self.enabled = bool(self.token and self.chat_id)
        if not self.enabled:
            logger.warning("Telegram Bot Token or Chat ID not found in environment variables.")

    def send_message(self, text: str):
        if not self.enabled:
            return

        url = f"https://api.telegram.org/bot{self.token}/sendMessage"
        payload = {
            "chat_id": self.chat_id,
            "text": text,
            "parse_mode": "HTML"
        }
        try:
            response = requests.post(url, json=payload)
            response.raise_for_status()
            logger.info("Notification sent successfully.")
        except Exception as e:
            logger.error(f"Failed to send notification: {e}")

notifier = TelegramNotifier()
